const response = $.steps.fetchUnread.response;
const messages = response.messages || response.data || [];
const maxEmails = $.input.maxEmails || 15;
const emails = [];

if (Array.isArray(messages)) {
  messages.slice(0, maxEmails).forEach((msg, i) => {
    const headers = msg.payload && msg.payload.headers ? msg.payload.headers : [];
    const getH = (n) => { const h = headers.find(h => h.name && h.name.toLowerCase() === n.toLowerCase()); return h ? h.value : ''; };
    emails.push({
      index: i + 1,
      id: msg.id || '',
      threadId: msg.threadId || '',
      from: getH('From') || msg.from || 'Unknown',
      to: getH('To') || msg.to || '',
      subject: getH('Subject') || msg.subject || '(no subject)',
      date: getH('Date') || msg.date || '',
      snippet: msg.snippet || msg.body || '',
      messageId: getH('Message-ID') || ''
    });
  });
}

let compiled = '';
emails.forEach(e => {
  compiled += 'EMAIL #' + e.index + ':\n';
  compiled += '  From: ' + e.from + '\n';
  compiled += '  Subject: ' + e.subject + '\n';
  compiled += '  Date: ' + e.date + '\n';
  compiled += '  Body: ' + e.snippet.slice(0, 500) + '\n\n';
});

return { compiled, emails, emailCount: emails.length };

const d = $.steps.compileEmails.output;
const tone = $.input.replyTone || 'professional';
const name = $.input.senderName || 'AI Assistant';

let prompt = 'You are an email response assistant. For each email below, assess whether it needs a reply, and if so, draft a ' + tone + ' response.\n\n';
prompt += 'SENDER NAME: ' + name + '\n';
prompt += 'EMAILS (' + d.emailCount + ' total):\n' + d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- For each email, first decide: NEEDS_REPLY, NO_REPLY_NEEDED, or SKIP (spam/newsletter)\n';
prompt += '- For emails needing a reply, draft a complete response\n';
prompt += '- Keep replies concise and ' + tone + '\n';
prompt += '- Do NOT reply to automated/no-reply emails, newsletters, or marketing\n';
prompt += '- Sign replies with "' + name + '"\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "replies": [\n';
prompt += '    {\n';
prompt += '      "emailIndex": 1,\n';
prompt += '      "from": "original sender",\n';
prompt += '      "subject": "original subject",\n';
prompt += '      "assessment": "NEEDS_REPLY|NO_REPLY_NEEDED|SKIP",\n';
prompt += '      "reason": "why this assessment",\n';
prompt += '      "draftReply": "full draft reply text or empty string",\n';
prompt += '      "replySubject": "Re: original subject"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "totalEmails": ' + d.emailCount + ',\n';
prompt += '  "needsReply": 0,\n';
prompt += '  "skipped": 0\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { replies: [], totalEmails: 0, needsReply: 0, skipped: 0 }; }

const ai = $.steps.parseAI.output;
const emailCount = $.steps.compileEmails.output.emailCount;
const replies = ai.replies || [];
const needsReply = replies.filter(r => r.assessment === 'NEEDS_REPLY');
const skipped = replies.filter(r => r.assessment === 'SKIP' || r.assessment === 'NO_REPLY_NEEDED');

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Gmail Auto-Responder Draft Review', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Emails Processed:*\n' + emailCount },
  { type: 'mrkdwn', text: '*Drafts Created:*\n' + needsReply.length },
  { type: 'mrkdwn', text: '*Skipped:*\n' + skipped.length }
] });
blocks.push({ type: 'divider' });

if (needsReply.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Drafted Replies for Review:*' } });
  needsReply.slice(0, 10).forEach((r, i) => {
    blocks.push({ type: 'divider' });
    let replyText = '*' + (i + 1) + '. Reply to: ' + (r.from || 'Unknown') + '*\n';
    replyText += '*Subject:* ' + (r.subject || '(no subject)') + '\n';
    replyText += '*Assessment:* ' + r.reason + '\n\n';
    replyText += '*Draft Reply:*\n';
    replyText += '```' + (r.draftReply || 'No draft').slice(0, 1200) + '```';
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: replyText.slice(0, 1800) } });
  });
} else {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '_No emails require a reply at this time._' } });
}

if (skipped.length > 0) {
  blocks.push({ type: 'divider' });
  let skipText = '*Skipped Emails:*\n';
  skipped.slice(0, 5).forEach((s, i) => {
    skipText += (i + 1) + '. ' + (s.subject || 'N/A') + ' from ' + (s.from || 'Unknown') + ' - _' + (s.reason || 'auto-skipped') + '_\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: skipText.slice(0, 1800) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':envelope: Review drafts above and send manually. | Powered by Gmail + Claude AI | One CLI' }] });

const fallbackText = 'Gmail Auto-Responder: ' + needsReply.length + ' drafts created from ' + emailCount + ' emails';
return { blocks, fallbackText, draftReplies: needsReply };
